var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color>","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Ground One</color>","TWN":"管理局直轄市<color=#ffd34c>G1</color>","SCN":"管理局直属城市 <color=#ffd34c>GroundOne</color>","DEU":"Administration Direct Control City, <color=#ffd34c>Ground One</color>","FRA":"Administration Direct Control City, <color=#ffd34c>Ground One</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"여기가 루퍼 자매님이 말했던 카페 스트레가인가?","JPN":"ここがシスター・シンディが言っていたカフェストレガかしら？","ENG":"Is this Cafe Strega that Sister Looper mentioned?","TWN":"這裡就是洛珀姊妹提到的史特雷加咖啡廳嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"원래 있던 곳에서 점포를 이전했다고 들었는데, 그게 그라운드 원이었구나.","JPN":"元の場所からお店を移転したと聞いたけど、それがグラウンド・ワンだったのね。","ENG":"I heard they moved their store from the previous location, so that was Ground One, huh?","TWN":"聽說你們從原來的地方搬遷了，原來是搬到了G1啊。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_A_NULL","text":{"KOREA":"윙스타 봤어? 지금 스트레가에서 크리스마스 한정 챌린지를 열었대!","JPN":"ウィングスター見た？　今ストレガで、クリスマス限定チャレンジがあるんだって！","ENG":"Did you see Wing-stagram? Strega just opened a Christmas-limited challenge!","TWN":"看限動了嗎？現在史特雷加正在舉辦聖誕限定挑戰賽！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_B_NULL","text":{"KOREA":"<color=#ffd34c>트리플 민트 초코 챌린지</color>? 진짜 이런 걸 하는 사람들이 있단 말이야?","JPN":"<color=#ffd34c>トリプルミントチョコチャレンジ</color>？　本当にこんなことをしてる人たちっているの？","ENG":"The <color=#ffd34c>Triple Mint Chocolate Challenge</color>? Do people really do these challenges?","TWN":"<color=#ffd34c>三重薄荷巧克力挑戰</color>？真的有人會做這種事嗎？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_A_NULL","text":{"KOREA":"요즘 유행이잖아~ 이 클립 좀 봐, 하트베리 애들도 벌써 도전하고 갔다고.","JPN":"最近流行ってるんだよ～これ見て、ハートベリーのみんなももうチャレンジしたって。","ENG":"It's all the rage! Look at this clip. Even HRT Berry already did the challenge.","TWN":"最近很流行喔～看看這個影片，愛心莓果都已經挑戰過了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"GIRLSTUDENT_NPC_A_NULL","text":{"KOREA":"숨겨온 칫솔에다가 민트 초코 발라서 이빨 닦는 루미가 완전 웃겨!","JPN":"こっそり持ってきた歯ブラシにミントチョコ塗って歯磨きしてるルミがウケる！","ENG":"Watching Lumi secretly bring her toothbrush just to put mint chocolate on it and brush her teeth is hilarious!","TWN":"魯米用藏起來的牙刷刷上薄荷巧克力刷牙，真是太搞笑了！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"GIRLSTUDENT_NPC_A_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GIRLSTUDENT_NPC_B_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"아, 아침 일찍부터 이렇게 손님이 붐빌 줄이야……!","JPN":"あ、朝早くからこんなにお客さんでいっぱいだなんて……！","ENG":"I-I didn't know it would be this crowded with customers so early in the morning...!","TWN":"啊，沒想到一大早就有這麼多客人……！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"특별한 컨셉의 카페라고 하더니, 아무래도 제대로 찾아온 것 같아.","JPN":"特別なコンセプトのカフェだって言ってたから、ここで合ってるみたいね。","ENG":"She did say the cafe had its own thing going on, so I guess I'm at the right place.","TWN":"說是有風格特別的咖啡廳，看來我找對地方了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"그래, 여기라면…….","JPN":"そう、ここなら……","ENG":"Yeah, I think...","TWN":"如果在這裡的話……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"특별한 날에 먹는 특별한 디저트에는 특별한 재료가 들어가기 마련이죠.","JPN":"特別な日に食べる特別なデザートには、特別な材料が入るものです。","ENG":"Special desserts for special days require special ingredients.","TWN":"在特別的日子裡吃的特別甜點，當然要用特別的材料。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"쇼콜라 무스 케이크의 포인트는 <color=#ffd34c>두 가지</color>라고 할 수 있습니다.","JPN":"ムースショコラのポイントは<color=#ffd34c>2つ</color>あります。","ENG":"In the case of a chocolate mousse cake, one can say there are <color=#ffd34c>two</color> important factors.","TWN":"巧克力慕斯蛋糕的亮點可以說有<color=#ffd34c>兩個方面</color>。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"바로 무스의 쫀득한 식감과 초콜릿의 씁쓸한 풍미의 조화죠.","JPN":"ムースのふんわりした食感と、チョコレートのほろ苦い風味の調和です。","ENG":"And those are the chewy texture of the mousse and the bitterness of the chocolate.","TWN":"就是慕斯的Q彈口感和巧克力的苦澀風味互相結合。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"과연, 식감과 풍미로군요……!","JPN":"なるほど、食感と風味ですね……！","ENG":"I see. So it's texture and flavor...!","TWN":"果然，口感和風味都很棒……！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇습니다. 먼저 무스는 계란 노른자와 설탕, 녹인 버터를 채로 잘 섞어 버터 크림을…….","JPN":"そうです。まず、ムースは卵の黄身と砂糖、溶かしたバターをよく混ぜてバタークリームを……","ENG":"That is correct. For the mousse, you will need to mix egg yolk with sugar and melted butter to make butter cream–","TWN":"是的。首先，將蛋黃、糖和融化的奶油混合均勻，製成奶油霜……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"자, 잠시만요! 메모할게요, 메모!","JPN":"ま、待ってください！　メモを取ります、メモ！","ENG":"W-wait! I need to write this down!","TWN":"等、等一下！我來記一下，記一下！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"계란과 설탕… 버터 크림을 만든다…….","JPN":"卵と砂糖……バタークリームを作る……","ENG":"Eggs and sugar... to make butter cream...","TWN":"雞蛋和糖……製作奶油霜……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그 뒤에 부드러운 생크림과 녹인 젤라틴을 넣어 무스를 완성합니다.","JPN":"それから柔らかい生クリームと溶かしたゼラチンを入れてムースを作ります。","ENG":"Afterward, add soft whipped cream and melted gelatin to complete the mousse.","TWN":"然後加入柔軟的鮮奶油和融化的吉利丁，完成慕斯。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"젤라틴이라고요……?","JPN":"ゼラチンですか……？","ENG":"Gelatin...?","TWN":"你說是吉利丁……？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"예. 무스의 식감을 결정하는 포인트가 바로 젤라틴입니다.","JPN":"はい。ムースの食感を決めるポイントがゼラチンなのですよ。","ENG":"Yes. Gelatin is what determines the texture.","TWN":"是的，決定慕斯口感的關鍵就是吉利丁。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤 종류의 젤라틴을 선택하고, 어떻게 다루느냐에 따라 특별한 식감을 줄 수 있거든요.","JPN":"どんな種類のゼラチンにするか、どのように仕上げるかによって特別な食感が生まれるのです。","ENG":"What type of gelatin and how you mix it will give it its special texture.","TWN":"根據選擇的吉利丁種類和處理方式，可以帶來特別的口感。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"요점은 너무 물러서도, 너무 단단해서도 안 된다는 겁니다.","JPN":"要は柔らかすぎず、固すぎずですね。","ENG":"The point is that it should not be too soft or too firm.","TWN":"重點是不能太軟，也不能太硬。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};